/* Generated by Axiom. Do not edit directly. */
export const axiomAuditContracts = [
  {
    "capability": "upload_receipt",
    "events": [
      "record upload_started",
      "record encrypted_blob_stored"
    ],
    "forbiddenLogFields": [
      "image_file"
    ]
  },
  {
    "capability": "extract_receipt_fields",
    "events": [
      "record extraction_started",
      "record extraction_completed"
    ],
    "forbiddenLogFields": [
      "plaintext_receipt",
      "receipt.image",
      "full receipt.text"
    ]
  },
  {
    "capability": "monthly_summary",
    "events": [],
    "forbiddenLogFields": []
  }
];

export function auditContractFor(capabilityKey) {
  return axiomAuditContracts.find((item) => item.capability === capabilityKey) || null;
}

export function createAuditEvent(capabilityKey, payload = {}) {
  const contract = auditContractFor(capabilityKey);
  if (!contract) {
    throw new Error(`Unknown Axiom audit capability: ${capabilityKey}`);
  }

  const forbidden = contract.forbiddenLogFields.filter((field) => Object.prototype.hasOwnProperty.call(payload, field));
  if (forbidden.length) {
    throw new Error(`Axiom audit payload for ${capabilityKey} includes forbidden field(s): ${forbidden.join(", ")}`);
  }

  return {
    capability: capabilityKey,
    events: contract.events,
    payload,
  };
}
